 try {
 var r = new sn_ws.RESTMessageV2('Google Gemini API', 'GenerateContent');
 r.setStringParameterNoEscape('prompt_text', vaInputs.user_prompt.getValue());

 var response = r.execute();
 var responseBody = response.getBody();
 var parsed = JSON.parse(responseBody);

 // This puts the Gemini text into our 'ai_answer' bucket
 vaVars.ai_answer = parsed.candidates[0].content.parts[0].text;
 } catch (ex) {
 vaVars.ai_answer = "Error: " + ex.message;
 }
})();
